module top_module(
    input [15:0] data_in,
    input [3:0] shift_amount,
    input shift_direction,
    output [15:0] data_out
);reg [15:0] unshifted_data;

always @(*) begin
    if (shift_direction == 1'b0) // right shift
        unshifted_data = data_in >> shift_amount;
    else // left shift
        unshifted_data = data_in << shift_amount;
end

assign data_out = unshifted_data;

endmodule
